import sys
from unittest import TestCase, main, skipUnless

try:
    from unittest.mock import patch, Mock
except ImportError:
    from mock import patch, Mock

from ..ansitowin32 import StreamWrapper
from ..initialise import init, just_fix_windows_console, _wipe_internal_state_for_tests
from .utils import osname, replace_by

orig_stdout = sys.stdout
orig_stderr = sys.stderr


class InitTest(TestCase):

    @skipUnless(sys.stdout.isatty(), "sys.stdout is not a tty")
    def setUp(self):
        """Prepare for each test by ensuring initial conditions are sane."""
        # sanity check
        self.assertNotWrapped()

    def tearDown(self):
        """Reset global state modified by tests."""
        _wipe_internal_state_for_tests()
        sys.stdout = orig_stdout
        sys.stderr = orig_stderr

    def assertWrapped(self):
        """Assert that stdout/stderr have been wrapped by StreamWrapper."""
        self.assertIsNot(sys.stdout, orig_stdout, 'stdout should be wrapped')
        self.assertIsNot(sys.stderr, orig_stderr, 'stderr should be wrapped')
        self.assertTrue(isinstance(sys.stdout, StreamWrapper),
            'bad stdout wrapper')
        self.assertTrue(isinstance(sys.stderr, StreamWrapper),
            'bad stderr wrapper')

    def assertNotWrapped(self):
        """Assert that stdout/stderr are the original streams (not wrapped)."""
        self.assertIs(sys.stdout, orig_stdout, 'stdout should not be wrapped')
        self.assertIs(sys.stderr, orig_stderr, 'stderr should not be wrapped')

    @patch('colorama.initialise.reset_all')
    @patch('colorama.ansitowin32.winapi_test', lambda *_: True)
    @patch('colorama.ansitowin32.enable_vt_processing', lambda *_: False)
    def testInitWrapsOnWindows(self, _):
        """On Windows with native winapi support, init() should wrap streams."""
        with osname("nt"):
            init()
            self.assertWrapped()

    @patch('colorama.initialise.reset_all')
    @patch('colorama.ansitowin32.winapi_test', lambda *_: False)
    def testInitDoesntWrapOnEmulatedWindows(self, _):
        """When Windows is emulated (no winapi), init() should not wrap."""
        with osname("nt"):
            init()
            self.assertNotWrapped()

    def testInitDoesntWrapOnNonWindows(self):
        """On non-Windows platforms, init() should not wrap by default."""
        with osname("posix"):
            init()
            self.assertNotWrapped()

    def testInitDoesntWrapIfNone(self):
        """If stdout/stderr are set to None, init() should leave them as None."""
        with replace_by(None):
            init()
            # We can't use assertNotWrapped here because replace_by(None)
            # changes stdout/stderr already.
            self.assertIsNone(sys.stdout)
            self.assertIsNone(sys.stderr)

    def testInitAutoresetOnWrapsOnAllPlatforms(self):
        """init(autoreset=True) should wrap streams on all platforms."""
        with osname("posix"):
            init(autoreset=True)
            self.assertWrapped()

    def testInitWrapOffDoesntWrapOnWindows(self):
        """If wrap=False on Windows, init() should not wrap stdout/stderr."""
        with osname("nt"):
            init(wrap=False)
            self.assertNotWrapped()

    def testInitWrapOffIncompatibleWithAutoresetOn(self):
        """Using wrap=False together with autoreset=True should raise ValueError."""
        self.assertRaises(ValueError, lambda: init(autoreset=True, wrap=False))

    @patch('colorama.win32.SetConsoleTextAttribute')
    @patch('colorama.initialise.AnsiToWin32')
    def testAutoResetPassedOn(self, mockATW32, _):
        """When autoreset=True, the AnsiToWin32 wrapper should receive autoreset=True."""
        with osname("nt"):
            init(autoreset=True)
            self.assertEqual(len(mockATW32.call_args_list), 2)
            self.assertEqual(mockATW32.call_args_list[1][1]['autoreset'], True)
            self.assertEqual(mockATW32.call_args_list[0][1]['autoreset'], True)

    @patch('colorama.initialise.AnsiToWin32')
    def testAutoResetChangeable(self, mockATW32):
        """Autoreset setting should be changeable by subsequent init() calls."""
        with osname("nt"):
            init()

            init(autoreset=True)
            self.assertEqual(len(mockATW32.call_args_list), 4)
            self.assertEqual(mockATW32.call_args_list[2][1]['autoreset'], True)
            self.assertEqual(mockATW32.call_args_list[3][1]['autoreset'], True)

            init()
            self.assertEqual(len(mockATW32.call_args_list), 6)
            self.assertEqual(
                mockATW32.call_args_list[4][1]['autoreset'], False)
            self.assertEqual(
                mockATW32.call_args_list[5][1]['autoreset'], False)


    @patch('colorama.initialise.atexit.register')
    def testAtexitRegisteredOnlyOnce(self, mockRegister):
        """atexit.register should be called only once even if init() is called multiple times."""
        init()
        init()
        self.assertEqual(mockRegister.call_count, 1)


class JustFixWindowsConsoleTest(TestCase):
    """Tests for just_fix_windows_console helper."""

    def _reset(self):
        """Reset global state modified by tests."""
        _wipe_internal_state_for_tests()
        sys.stdout = orig_stdout
        sys.stderr = orig_stderr

    def tearDown(self):
        """Teardown for each test in this class."""
        self._reset()

    def testJustFixWindowsConsole(self):
        """Ensure just_fix_windows_console runs without raising on fake streams."""
        s_out, s_err = self.fake_std()
        saved_out, saved_err = sys.stdout, sys.stderr
        try:
            sys.stdout = s_out
            sys.stderr = s_err
            # Call the function under test; primarily we ensure it doesn't raise.
            just_fix_windows_console()
        finally:
            sys.stdout = saved_out
            sys.stderr = saved_err

    def fake_std(self):
        """Return a pair of fake stdout/stderr-like objects for testing."""
        class FakeStream(object):
            def __init__(self):
                self.encoding = 'utf-8'
                self._written = []
            def write(self, s):
                self._written.append(s)
            def isatty(self):
                return True
            def fileno(self):
                # Provide a plausible file descriptor
                return 1
            def flush(self):
                pass
        return FakeStream(), FakeStream()


if __name__ == '__main__':
    main()